const path = require('path');

const { getTsconfig } = require('get-tsconfig');

const { NORDIC_BUILD_DIR } = require('./constants');

const configDir = process.env.NODE_CONFIG_DIR || 'config';

const getAppConfig = () => {
  try {
    // eslint-disable-next-line import/no-dynamic-require, security/detect-non-literal-require
    return require(path.resolve(configDir, 'default'));
  } catch (error) {
    return null;
  }
};

/**
 * Resolve aliases from jsconfig.json or tsconfig.json, if not defined in options
 * @param {Object} options - The options for resolving aliases
 * @param {boolean} options.isWebpack - If the aliases are for the client
 * @param {boolean} options.isExternal - If the aliases are for an external or environment
 * @param {string} [options.rootPath] - The root path to resolve the aliases from
 * @param {boolean} [options.isBabelClient] - If the aliases are for babel client
 */
function resolveAliases({
  isWebpack,
  isExternal,
  rootPath = '.',
  isBabelClient = false,
}) {
  if (!isExternal && !getAppConfig()?.modulePathAliases) {
    return null;
  }

  const tsCompilerOptions =
    getTsconfig(rootPath, 'tsconfig.json')?.config?.compilerOptions ||
    getTsconfig(rootPath, 'jsconfig.json')?.config?.compilerOptions;

  const { paths, baseUrl } = tsCompilerOptions || {};

  if (!paths || !baseUrl) {
    return null;
  }

  /** @type {Record<string,string|string[]>} */
  const resolvedPaths = {};

  Object.entries(paths).forEach(([key, value]) => {
    const newKey = key.replace('/*', '');

    if (value.some((aliasPath) => aliasPath.includes('node_modules'))) {
      if (isWebpack) {
        resolvedPaths[newKey] = value.map((val) =>
          path.resolve(rootPath, val.replace('/*', '')),
        );

        return;
      }

      resolvedPaths[newKey] = path.resolve(value[0].replace('/*', ''));

      return;
    }

    if (value.length !== 1) {
      throw new Error(
        'Alias value must be a single string array: "@alias": ["./path/to/file/*"]. Fix your tsconfig.json or jsconfig.json to continue.',
      );
    }

    const originalPath = value[0].replace('/*', '');
    const tempPaths = [];

    let buildPath;

    if (
      tsCompilerOptions?.outDir?.includes(NORDIC_BUILD_DIR) &&
      !process.argv.includes('ts-node/register')
    ) {
      buildPath = path.join(tsCompilerOptions.outDir, originalPath);
    }

    if (isWebpack) {
      if (buildPath) {
        tempPaths.push(path.resolve(rootPath, buildPath));
      }

      tempPaths.push(path.resolve(rootPath, originalPath));
      resolvedPaths[newKey] = tempPaths;

      return;
    }

    resolvedPaths[newKey] =
      buildPath && !isBabelClient
        ? path.resolve(rootPath, buildPath)
        : path.resolve(rootPath, originalPath);
  });

  return isWebpack ? resolvedPaths : { root: [baseUrl], alias: resolvedPaths };
}

module.exports = resolveAliases;
